func processData(items []int) []int {
	results := make([]int, len(items))
	ch := make(chan int, len(items))

	for _, item := range items {
		go func(val int) {
			ch <- val * 2
		}(item)
	}

	for i := 0; i < len(items); i++ {
		results[i] = <-ch
	}

	return results
}
